export default function MedicineCard({ medicine }) {
	return (
		<div className="card">
			<h3>{medicine.name}</h3>
			<p>Shop: {medicine.shop_name}</p>
			<p>Price: Rs {medicine.price}</p>
			<p>In Stock: {medicine.in_stock ? "Yes" : "No"}</p>
		</div>
	);
}
